import json, os

CONFIG_DIR = os.path.join(os.path.expanduser('~'), '.voice-doc-compare')
CONFIG_FILE = os.path.join(CONFIG_DIR, 'config.json')

ASR_PROVIDERS = {
    'aliyun': {'name': '阿里云语音识别', 'region': 'cn', 'fields': ['key', 'secret', 'appKey']},
    'baidu': {'name': '百度语音识别', 'region': 'cn', 'fields': ['key', 'secret', 'appKey']},
    'funasr': {'name': 'FunASR(本地)', 'region': 'cn', 'fields': []},
    'groq_whisper': {'name': 'Groq Whisper', 'region': 'intl', 'fields': ['key']},
    'openai_whisper': {'name': 'OpenAI Whisper', 'region': 'intl', 'fields': ['key']},
}

LLM_PROVIDERS = {
    # 国内八家
    'zhipu': {'name': '智谱GLM', 'region': 'cn', 'endpoint': 'https://open.bigmodel.cn/api/paas/v4/chat/completions', 'default_model': 'glm-4'},
    'deepseek': {'name': 'DeepSeek', 'region': 'cn', 'endpoint': 'https://api.deepseek.com/v1/chat/completions', 'default_model': 'deepseek-chat'},
    'qwen': {'name': '通义千问', 'region': 'cn', 'endpoint': 'https://dashscope.aliyuncs.com/compatible-mode/v1/chat/completions', 'default_model': 'qwen-turbo'},
    'moonshot': {'name': 'Kimi(月之暗面)', 'region': 'cn', 'endpoint': 'https://api.moonshot.cn/v1/chat/completions', 'default_model': 'moonshot-v1-8k'},
    'baichuan': {'name': '百川智能', 'region': 'cn', 'endpoint': 'https://api.baichuan-ai.com/v1/chat/completions', 'default_model': 'Baichuan4'},
    'minimax': {'name': 'MiniMax', 'region': 'cn', 'endpoint': 'https://api.minimax.chat/v1/text/chatcompletion_v2', 'default_model': 'abab6.5s-chat'},
    'stepfun': {'name': '阶跃星辰', 'region': 'cn', 'endpoint': 'https://api.stepfun.com/v1/chat/completions', 'default_model': 'step-1-8k'},
    'doubao': {'name': '豆包(字节)', 'region': 'cn', 'endpoint': 'https://ark.cn-beijing.volces.com/api/v3/chat/completions', 'default_model': 'doubao-pro-4k'},
    # 国际八家
    'openai': {'name': 'OpenAI', 'region': 'intl', 'endpoint': 'https://api.openai.com/v1/chat/completions', 'default_model': 'gpt-4o-mini'},
    'claude': {'name': 'Claude', 'region': 'intl', 'endpoint': 'https://api.anthropic.com/v1/messages', 'default_model': 'claude-sonnet-4-20250514'},
    'gemini': {'name': 'Gemini', 'region': 'intl', 'endpoint': 'https://generativelanguage.googleapis.com/v1beta/chat/completions', 'default_model': 'gemini-2.0-flash'},
    'groq': {'name': 'Groq', 'region': 'intl', 'endpoint': 'https://api.groq.com/openai/v1/chat/completions', 'default_model': 'llama-3.1-70b-versatile'},
    'mistral': {'name': 'Mistral', 'region': 'intl', 'endpoint': 'https://api.mistral.ai/v1/chat/completions', 'default_model': 'mistral-large-latest'},
    'cohere': {'name': 'Cohere', 'region': 'intl', 'endpoint': 'https://api.cohere.com/v2/chat', 'default_model': 'command-r-plus'},
    'perplexity': {'name': 'Perplexity', 'region': 'intl', 'endpoint': 'https://api.perplexity.ai/chat/completions', 'default_model': 'sonar-pro'},
    'together': {'name': 'Together AI', 'region': 'intl', 'endpoint': 'https://api.together.xyz/v1/chat/completions', 'default_model': 'meta-llama/Llama-3-70b-chat-hf'},
}

DEFAULT_CONFIG = {
    'asr_provider': 'funasr',
    'llm_provider': 'zhipu',
    'asr_keys': {},
    'llm_keys': {},
}

def load_config():
    if os.path.exists(CONFIG_FILE):
        try:
            with open(CONFIG_FILE, 'r', encoding='utf-8') as f:
                return {**DEFAULT_CONFIG, **json.load(f)}
        except Exception:
            pass
    return dict(DEFAULT_CONFIG)

def save_config(config):
    os.makedirs(CONFIG_DIR, exist_ok=True)
    with open(CONFIG_FILE, 'w', encoding='utf-8') as f:
        json.dump(config, f, ensure_ascii=False, indent=2)

def is_valid(config):
    pid = config['asr_provider']
    if pid == 'funasr':
        return True
    return bool(config.get('asr_keys', {}).get(pid, {}).get('key'))

import requests, json, re
import jieba
from difflib import SequenceMatcher
from jiwer import wer, cer
from pypinyin import pinyin, Style

FILLER_WORDS = {'嗯', '呃', '啊', '哦', '呢', '吧', '嘛', '哈', '噢', '诶',
                '那个', '就是', '就是说', '然后', '对吧', '对的', '这个',
                '那', '所以', '但是', '不过', '其实', '反正', '好的'}

def _same_pinyin(a, b):
    """Return True if two strings have identical pinyin with tones (char-by-char)."""
    if not a or not b:
        return False
    # Remove punctuation before comparing
    a_clean = _normalize(a) if hasattr(_normalize, '__call__') else re.sub(r'[，。！？；：、\s,.!?;:]', '', a)
    b_clean = _normalize(b) if hasattr(_normalize, '__call__') else re.sub(r'[，。！？；：、\s,.!?;:]', '', b)
    if not a_clean or not b_clean or len(a_clean) != len(b_clean):
        return False
    pa = pinyin(a_clean, style=Style.TONE3, neutral_tone_with_five=True)
    pb = pinyin(b_clean, style=Style.TONE3, neutral_tone_with_five=True)
    return pa == pb

def _is_punct(ch):
    return bool(re.match(r'[，。！？；：、\u201c\u201d\u2018\u2019（）【】《》…—·\s,.!?;:\'"()\[\]{}\-]', ch))

def _normalize(text):
    """Remove punctuation for comparison."""
    return re.sub(r'[，。！？；：、\u201c\u201d\u2018\u2019（）【】《》…—·\s,.!?;:\'"()\[\]{}\-]', '', text)

def _punct_only_diff(a, b):
    """Return True if a and b differ only in punctuation (same chars after removing punct)."""
    return _normalize(a) == _normalize(b)

def _get_sentence_breaks(text):
    """Extract sentence break positions (char offsets after removing punct) from sentence-ending punctuation."""
    breaks = []
    char_idx = 0
    for ch in text:
        if _is_punct(ch):
            if ch in '。！？.!?\n':
                breaks.append(char_idx)
        else:
            char_idx += 1
    return breaks

def _sentence_breaks_match(doc_text, audio_text):
    """Check if audio sentence breaks align with doc sentence breaks."""
    doc_breaks = _get_sentence_breaks(doc_text)
    audio_breaks = _get_sentence_breaks(audio_text)
    if not doc_breaks and not audio_breaks:
        return True
    if not doc_breaks or not audio_breaks:
        return len(doc_breaks) == len(audio_breaks)
    return doc_breaks == audio_breaks

def _segment(text):
    """Jieba word segmentation, filter empty tokens."""
    return [w for w in jieba.cut(text) if w.strip()]

def _find_paragraph(doc_paragraphs, doc_text_norm, word_pos, doc_words):
    """Map a word position in doc_words back to paragraph index."""
    # Build char offset for each word
    char_offset = 0
    for i, w in enumerate(doc_words):
        if i == word_pos:
            break
        char_offset += len(w)
    # Find which paragraph this char offset falls in
    running = 0
    for idx, p in enumerate(doc_paragraphs):
        plen = len(_normalize(p))
        if running + plen > char_offset:
            return idx
        running += plen
    return len(doc_paragraphs) - 1

def compare_texts(audio_text, doc_text, config, word_timestamps=None):
    """Algorithm-based word-level diff using jieba + SequenceMatcher."""
    doc_paragraphs = [p.strip() for p in doc_text.split('\n') if p.strip()]
    confidence_threshold = config.get('confidence_threshold', 0.0)

    # Normalize and segment
    audio_norm = _normalize(audio_text)
    doc_norm = _normalize(doc_text)
    audio_words = _segment(audio_norm)
    doc_words = _segment(doc_norm)

    # Build char->timestamp mapping from word_timestamps
    ts_map = {}  # audio char offset -> {start, end, confidence}
    if word_timestamps:
        offset = 0
        for wt in word_timestamps:
            w = _normalize(wt['word'])
            for i in range(len(w)):
                ts_map[offset + i] = {'start': wt['start'], 'end': wt['end'], 'confidence': wt.get('confidence', 1.0)}
            offset += len(w)

    # Diff
    matcher = SequenceMatcher(None, doc_words, audio_words)
    raw_diffs = []

    # Track audio char offset per audio_words position
    audio_char_offsets = []
    off = 0
    for w in audio_words:
        audio_char_offsets.append(off)
        off += len(w)

    for tag, i1, i2, j1, j2 in matcher.get_opcodes():
        if tag == 'equal':
            continue

        doc_fragment = ''.join(doc_words[i1:i2])
        audio_fragment = ''.join(audio_words[j1:j2])

        # Skip filler words
        if tag == 'insert' and audio_fragment in FILLER_WORDS:
            continue
        if tag == 'delete' and doc_fragment in FILLER_WORDS:
            continue
        if tag == 'replace':
            if doc_fragment in FILLER_WORDS and audio_fragment in FILLER_WORDS:
                continue
            # Same pinyin+tone = same pronunciation, not a real diff
            if _same_pinyin(doc_fragment, audio_fragment):
                continue
            # Punctuation-only difference: if sentence breaks match, not a diff
            if _punct_only_diff(doc_fragment, audio_fragment):
                if _sentence_breaks_match(doc_fragment, audio_fragment):
                    continue

        # Skip single punctuation or whitespace-only diffs
        if not doc_fragment.strip() and not audio_fragment.strip():
            continue
        # Skip pure punctuation fragments
        if all(_is_punct(c) for c in doc_fragment) and all(_is_punct(c) or not c.strip() for c in audio_fragment):
            if _sentence_breaks_match(doc_fragment, audio_fragment):
                continue

        pos = _find_paragraph(doc_paragraphs, doc_norm, i1, doc_words)

        # Get timestamp and confidence for this diff
        ts_start = ts_end = None
        confidence = 1.0
        if ts_map and j1 < len(audio_char_offsets):
            char_off = audio_char_offsets[j1]
            if char_off in ts_map:
                ts_start = ts_map[char_off]['start']
                confidence = ts_map[char_off]['confidence']
            if j2 > 0 and j2 - 1 < len(audio_char_offsets):
                end_off = audio_char_offsets[j2 - 1]
                if end_off in ts_map:
                    ts_end = ts_map[end_off]['end']

        diff_entry = {
            'docText': doc_fragment,
            'audioText': audio_fragment,
            'type': 'mismatch' if tag == 'replace' else ('missing_in_audio' if tag == 'delete' else 'extra_in_audio'),
            'position': pos,
            'confidence': confidence,
            'uncertain': confidence < confidence_threshold if confidence_threshold > 0 else False,
        }
        if ts_start is not None:
            diff_entry['time_start'] = ts_start
        if ts_end is not None:
            diff_entry['time_end'] = ts_end

        raw_diffs.append(diff_entry)

    n_mismatch = sum(1 for d in raw_diffs if d['type'] == 'mismatch')
    n_missing = sum(1 for d in raw_diffs if d['type'] == 'missing_in_audio')
    n_extra = sum(1 for d in raw_diffs if d['type'] == 'extra_in_audio')

    # Check sentence break alignment
    break_ok = _sentence_breaks_match(doc_text, audio_text)
    break_note = '' if break_ok else '\n⚠ 语音断句位置与原文不一致'

    # WER/CER metrics
    doc_str = ' '.join(doc_words)
    audio_str = ' '.join(audio_words)
    wer_val = wer(doc_str, audio_str) if doc_str else 0
    cer_val = cer(doc_norm, audio_norm) if doc_norm else 0
    accuracy_word = max(0, (1 - wer_val) * 100)
    accuracy_char = max(0, (1 - cer_val) * 100)

    summary = (f'共{len(raw_diffs)}处差异：{n_mismatch}处误读，{n_missing}处漏读，{n_extra}处多读{break_note}\n'
               f'词准确率 {accuracy_word:.1f}% | 字准确率 {accuracy_char:.1f}%')

    return {
        'diffs': raw_diffs, 'summary': summary,
        'wer': wer_val, 'cer': cer_val,
        'accuracy_word': accuracy_word, 'accuracy_char': accuracy_char,
    }

# --- LLM calls kept for test_llm ---
def _call_claude(prompt, api_key, model):
    r = requests.post('https://api.anthropic.com/v1/messages', timeout=60,
        headers={'Content-Type': 'application/json', 'x-api-key': api_key, 'anthropic-version': '2023-06-01'},
        json={'model': model, 'max_tokens': 4096, 'messages': [{'role': 'user', 'content': prompt}]})
    data = r.json()
    return data.get('content', [{}])[0].get('text', '')

def _call_openai_compat(prompt, api_key, endpoint, model):
    r = requests.post(endpoint, timeout=60,
        headers={'Content-Type': 'application/json', 'Authorization': f'Bearer {api_key}'},
        json={'model': model, 'messages': [{'role': 'user', 'content': prompt}], 'temperature': 0.1})
    data = r.json()
    return data.get('choices', [{}])[0].get('message', {}).get('content', '')

def test_llm(provider_id, api_key, model=None):
    from config import LLM_PROVIDERS
    provider = LLM_PROVIDERS[provider_id]
    m = model or provider['default_model']
    prompt = '请回复"连接成功"四个字。'
    try:
        if provider_id == 'claude':
            content = _call_claude(prompt, api_key, m)
        else:
            content = _call_openai_compat(prompt, api_key, provider['endpoint'], m)
        return (True, f'连接成功: {content[:50]}') if content else (False, '无响应')
    except Exception as e:
        return False, f'连接失败: {e}'

import os, time, html

def _fmt(seconds):
    if seconds is None: return ''
    m, s = divmod(int(seconds), 60)
    return f'{m}:{s:02d}'

def generate_html_report(diffs, summary, audio_text, doc_text, audio_path=None, output_dir=None):
    if output_dir is None:
        output_dir = os.path.join(os.path.expanduser('~'), 'Desktop')

    doc_paragraphs = [p.strip() for p in doc_text.split('\n') if p.strip()]

    # Build annotated paragraphs
    diff_by_pos = {}
    for d in diffs:
        diff_by_pos.setdefault(d.get('position', 0), []).append(d)

    annotated = []
    for idx, para in enumerate(doc_paragraphs):
        if idx not in diff_by_pos:
            annotated.append(html.escape(para))
            continue

        para_diffs = diff_by_pos[idx]
        located = []
        used = set()
        for d in para_diffs:
            dt = d.get('docText', '')
            if d.get('type') == 'extra_in_audio' or not dt:
                located.append((len(para), len(para), d))
                continue
            start = 0
            while True:
                pos = para.find(dt, start)
                if pos == -1:
                    located.append((len(para), len(para), d))
                    break
                if pos not in used:
                    used.add(pos)
                    located.append((pos, pos + len(dt), d))
                    break
                start = pos + 1
        located.sort(key=lambda x: x[0])

        parts = []
        cursor = 0
        for start, end, d in located:
            dtype = d.get('type', 'mismatch')
            at = html.escape(d.get('audioText', ''))
            ts = _fmt(d.get('time_start'))
            uncertain = ' uncertain' if d.get('uncertain') else ''
            ts_attr = f' data-time="{d["time_start"]}"' if d.get('time_start') is not None else ''
            ts_label = f' <span class="ts">@{ts}</span>' if ts else ''

            if start > cursor:
                parts.append(html.escape(para[cursor:start]))

            if dtype == 'mismatch':
                parts.append(f'<span class="diff mismatch{uncertain}"{ts_attr}>{html.escape(para[start:end])}'
                             f'<span class="note">[误读为:"{at}"{ts_label}]</span></span>')
            elif dtype == 'missing_in_audio':
                parts.append(f'<span class="diff missing{uncertain}"{ts_attr}>{html.escape(para[start:end])}'
                             f'<span class="note">[漏读{ts_label}]</span></span>')
            elif dtype == 'extra_in_audio':
                parts.append(f'<span class="diff extra{uncertain}"{ts_attr}>'
                             f'<span class="note">[多读:"{at}"{ts_label}]</span></span>')
            cursor = end

        if cursor < len(para):
            parts.append(html.escape(para[cursor:]))
        annotated.append(''.join(parts))

    audio_tag = ''
    if audio_path and os.path.exists(audio_path):
        audio_tag = f'<audio id="player" controls src="file:///{audio_path.replace(os.sep, "/")}"></audio>'

    body = '\n'.join(f'<p>{a}</p>' for a in annotated)
    summary_html = html.escape(summary).replace('\n', '<br>')

    content = f'''<!DOCTYPE html>
<html lang="zh"><head><meta charset="utf-8"><title>配音对比报告</title>
<style>
body {{ font-family: "Microsoft YaHei", sans-serif; max-width: 900px; margin: 40px auto; padding: 0 20px; line-height: 1.8; background: linear-gradient(135deg, #FFF8E1, #FFF3E0, #FFEBEE); }}
.summary {{ background: linear-gradient(90deg, #FFF8E1, #FFF3E0); padding: 16px; border-radius: 8px; margin-bottom: 24px; font-size: 15px; border-left: 4px solid #FFA726; }}
.diff {{ position: relative; cursor: pointer; }}
.mismatch {{ color: #d32f2f; font-weight: bold; text-decoration: underline; }}
.missing {{ color: #d32f2f; font-weight: bold; text-decoration: line-through; }}
.extra {{ color: #e65100; }}
.uncertain {{ opacity: 0.6; font-style: italic; }}
.note {{ font-size: 12px; font-weight: bold; color: #d32f2f; }}
.ts {{ color: #1565c0; font-size: 11px; }}
p {{ margin: 8px 0; font-size: 16px; }}
audio {{ width: 100%; margin-bottom: 16px; }}
.legend {{ display: flex; gap: 20px; margin-bottom: 16px; font-size: 13px; background: linear-gradient(90deg, #E8F5E9, #E3F2FD, #F3E5F5); padding: 8px 12px; border-radius: 8px; }}
.legend span {{ padding: 2px 8px; border-radius: 4px; }}
</style></head><body>
<h2 style="color:#FF6B6B;">配音质量核查报告</h2>
<div class="summary">{summary_html}</div>
<div class="legend">
<span class="mismatch">误读</span>
<span class="missing">漏读</span>
<span style="color:#e65100">多读</span>
</div>
{audio_tag}
<div id="content">{body}</div>
<script>
document.querySelectorAll('.diff[data-time]').forEach(el => {{
  el.addEventListener('click', () => {{
    const player = document.getElementById('player');
    if (player) {{ player.currentTime = parseFloat(el.dataset.time); player.play(); }}
  }});
}});
</script>
<footer style="text-align:center;color:#999;padding:20px;font-size:12px;">单夫纯制作，保留权利</footer>
</body></html>'''

    ts = time.strftime('%Y%m%d_%H%M%S')
    path = os.path.join(output_dir, f'对比报告_{ts}.html')
    with open(path, 'w', encoding='utf-8') as f:
        f.write(content)
    return path

